{
  "$schema": "https://raw.githubusercontent.com/oasis-tcs/sarif-spec/main/sarif-2.1/schema/sarif-schema-2.1.0.json",
  "version": "2.1.0",
  "runs": [
    {
      "tool": {
        "driver": {
          "name": "OJS-SAST",
          "version": "1.0.0",
          "informationUri": "https://github.com/ojs-sast/ojs-sast",
          "rules": [
            {
              "id": "CVE-SRC-47271",
              "name": "RCE via Path Traversal in NativeImportExportPlugin cover_image (CVE-2023-47271)",
              "shortDescription": {
                "text": "RCE via Path Traversal in NativeImportExportPlugin cover_image (CVE-2023-47271)"
              },
              "fullDescription": {
                "text": "\nThe Native XML import/export plugin reads the XML cover_image value from DOMElement textContent and uses it as a server-side uploadName. The value is later concatenated into a context file path and written with file_put_contents() using decoded embed content. If the cover_image value is not strictly sanitized, an authenticated user with access to the Native XML import/export plugin may perform path traversal and write or overwrite arbitrary files. In vulnerable deployments, this can lead to remote code execution."
              },
              "defaultConfiguration": {
                "level": "error"
              },
              "helpUri": "CVE-2023-47271",
              "properties": {
                "tags": [
                  "source_code",
                  "",
                  "CWE-22",
                  "external/cwe/cwe-22",
                  "A01:2021"
                ],
                "security-severity": "9.1"
              }
            },
            {
              "id": "RULE-UPLOAD-003",
              "name": "MIME type does not match file extension",
              "shortDescription": {
                "text": "MIME type does not match file extension"
              },
              "fullDescription": {
                "text": "File declares '.txt' extension but its content is PHP (text/x-php)."
              },
              "defaultConfiguration": {
                "level": "error"
              },
              "helpUri": "",
              "properties": {
                "tags": [
                  "uploaded_file",
                  "mime_mismatch",
                  "CWE-434",
                  "external/cwe/cwe-434",
                  "A05:2021"
                ]
              }
            },
            {
              "id": "RULE-UPLOAD-001",
              "name": "Dangerous file extension in upload directory",
              "shortDescription": {
                "text": "Dangerous file extension in upload directory"
              },
              "fullDescription": {
                "text": "Executable PHP extension '.php' found in an upload directory."
              },
              "defaultConfiguration": {
                "level": "error"
              },
              "helpUri": "",
              "properties": {
                "tags": [
                  "uploaded_file",
                  "dangerous_extension",
                  "CWE-434",
                  "external/cwe/cwe-434",
                  "A05:2021"
                ]
              }
            },
            {
              "id": "CVE-SRC-5626",
              "name": "CSRF in Payment Types Form Missing FormValidatorCSRF (CVE-2023-5626)",
              "shortDescription": {
                "text": "CSRF in Payment Types Form Missing FormValidatorCSRF (CVE-2023-5626)"
              },
              "fullDescription": {
                "text": "\nThe PaymentTypesForm constructor defines validators for payment-related fields but does not add a CSRF validator. Because the form performs state-changing payment configuration updates, a privileged user's browser may be tricked into submitting a forged request that alters subscription or payment settings."
              },
              "defaultConfiguration": {
                "level": "error"
              },
              "helpUri": "CVE-2023-5626",
              "properties": {
                "tags": [
                  "source_code",
                  "",
                  "CWE-352",
                  "external/cwe/cwe-352",
                  "A01:2021"
                ],
                "security-severity": "8.8"
              }
            },
            {
              "id": "CVE-SRC-67890",
              "name": "Path Traversal in NativeXmlIssueGalleyFilter file_name Handling (CVE-2025-67890)",
              "shortDescription": {
                "text": "Path Traversal in NativeXmlIssueGalleyFilter file_name Handling (CVE-2025-67890)"
              },
              "fullDescription": {
                "text": "\nThe Native XML import filter reads the XML file_name element and assigns its textContent directly as the server-side file name using setServerFileName(). Because the value is not sanitized, an authenticated user with access to the Native XML import/export plugin may supply path traversal sequences or unsafe path components. The resulting server-side file name can later be used by file write logic, leading to arbitrary file write or overwrite. In some deployments, this may lead to remote code execution if the attacker can target a web-accessible path."
              },
              "defaultConfiguration": {
                "level": "error"
              },
              "helpUri": "CVE-2025-67890",
              "properties": {
                "tags": [
                  "source_code",
                  "",
                  "CWE-22",
                  "external/cwe/cwe-22",
                  "A01:2021"
                ],
                "security-severity": "8.8"
              }
            },
            {
              "id": "CVE-SRC-67893",
              "name": "LESS Code Injection in baseColour DefaultThemePlugin (CVE-2025-67893)",
              "shortDescription": {
                "text": "LESS Code Injection in baseColour DefaultThemePlugin (CVE-2025-67893)"
              },
              "fullDescription": {
                "text": "\nThe baseColour theme option is concatenated directly into a LESS variable assignment without strict validation. An authenticated user with access to the Theme Settings API may store a malicious baseColour value, which is later inserted into $additionalLessVariables as @bg-base and parsed by the LESS compiler. This can lead to LESS code injection, potentially enabling SSRF or local file read depending on LESS parser behavior and runtime configuration."
              },
              "defaultConfiguration": {
                "level": "error"
              },
              "helpUri": "CVE-2025-67893",
              "properties": {
                "tags": [
                  "source_code",
                  "",
                  "CWE-94",
                  "external/cwe/cwe-94",
                  "A03:2021"
                ],
                "security-severity": "0.0"
              }
            },
            {
              "id": "OJS-CFG-SEC-005",
              "name": "Default or weak security salt — password reset hashes are predictable",
              "shortDescription": {
                "text": "Default or weak security salt — password reset hashes are predictable"
              },
              "fullDescription": {
                "text": "'salt' is set to a known default ('YouMustSetASecretKeyHere!!')."
              },
              "defaultConfiguration": {
                "level": "error"
              },
              "helpUri": "",
              "properties": {
                "tags": [
                  "config",
                  "",
                  "CWE-1188",
                  "external/cwe/cwe-1188",
                  "A05:2021"
                ],
                "security-severity": "7.5"
              }
            },
            {
              "id": "CVE-SRC-5894",
              "name": "Stored XSS in Issue Title Edit Modal (CVE-2023-5894)",
              "shortDescription": {
                "text": "Stored XSS in Issue Title Edit Modal (CVE-2023-5894)"
              },
              "fullDescription": {
                "text": "\nThe issue title returned by $issue->getIssueIdentification() is passed directly into the __() translation helper as the issueIdentification parameter without HTML escaping. Because issue titles can be configured by users with editor privileges, malicious HTML or JavaScript may be stored and later rendered in the Edit Issue Ajax modal, resulting in stored cross-site scripting."
              },
              "defaultConfiguration": {
                "level": "warning"
              },
              "helpUri": "CVE-2023-5894",
              "properties": {
                "tags": [
                  "source_code",
                  "",
                  "CWE-79",
                  "external/cwe/cwe-79",
                  "A03:2021"
                ],
                "security-severity": "5.4"
              }
            },
            {
              "id": "CVE-SRC-67892",
              "name": "Login CSRF in Validation::login (CVE-2025-67892)",
              "shortDescription": {
                "text": "Login CSRF in Validation::login (CVE-2025-67892)"
              },
              "fullDescription": {
                "text": "\nThe login handler processes authentication requests without validating the submitted CSRF token on the server side. Although the login form may send a csrfToken parameter, the server-side Validation::login() method does not call $request->checkCSRF() before validating credentials and establishing an authenticated session. This allows login CSRF, where an attacker may force a victim browser to authenticate into an attacker- controlled account."
              },
              "defaultConfiguration": {
                "level": "warning"
              },
              "helpUri": "CVE-2025-67892",
              "properties": {
                "tags": [
                  "source_code",
                  "",
                  "CWE-352",
                  "external/cwe/cwe-352",
                  "A01:2021"
                ],
                "security-severity": "6.5"
              }
            },
            {
              "id": "SAST-SRC-LESS-001",
              "name": "Potential LESS Variable Injection from Unsanitized Theme Option",
              "shortDescription": {
                "text": "Potential LESS Variable Injection from Unsanitized Theme Option"
              },
              "fullDescription": {
                "text": "\nA user-controlled or stored theme option appears to be concatenated into a LESS variable assignment. If the value is not strictly allowlisted before being passed to a LESS parser, an attacker may inject additional LESS syntax. This may lead to server-side request forgery, local file read, or other parser-dependent impact."
              },
              "defaultConfiguration": {
                "level": "warning"
              },
              "helpUri": "",
              "properties": {
                "tags": [
                  "source_code",
                  "",
                  "CWE-94",
                  "external/cwe/cwe-94",
                  "A03:2021"
                ],
                "security-severity": "6.5"
              }
            },
            {
              "id": "CVE-SRC-5903",
              "name": "Stored XSS in Section Title Rendering on Submissions Page (CVE-2023-5903)",
              "shortDescription": {
                "text": "Stored XSS in Section Title Rendering on Submissions Page (CVE-2023-5903)"
              },
              "fullDescription": {
                "text": "\nThe submissions page passes the localized section title into a Smarty {translate} parameter without escaping. The value returned by $section->getLocalizedTitle() may be controlled by a privileged user who can create or edit journal sections. When rendered on the frontend submissions page, malicious HTML or JavaScript in the section title may execute in a victim's browser, resulting in stored cross-site scripting."
              },
              "defaultConfiguration": {
                "level": "warning"
              },
              "helpUri": "CVE-2023-5903",
              "properties": {
                "tags": [
                  "source_code",
                  "",
                  "CWE-79",
                  "external/cwe/cwe-79",
                  "A03:2021"
                ],
                "security-severity": "5.4"
              }
            },
            {
              "id": "CVE-SRC-13469",
              "name": "Stored XSS in Manual Payment Instructions (CVE-2025-13469)",
              "shortDescription": {
                "text": "Stored XSS in Manual Payment Instructions (CVE-2025-13469)"
              },
              "fullDescription": {
                "text": "\nThe Manual Payment Plugin renders the manualInstructions setting directly into the payment checkout page using only the Smarty nl2br modifier. The nl2br modifier preserves line breaks but does not neutralize unsafe HTML or JavaScript. A high-privilege user who can configure manual payment instructions may store malicious markup that later executes in a victim's browser during checkout."
              },
              "defaultConfiguration": {
                "level": "warning"
              },
              "helpUri": "CVE-2025-13469",
              "properties": {
                "tags": [
                  "source_code",
                  "",
                  "CWE-79",
                  "external/cwe/cwe-79",
                  "A03:2021"
                ],
                "security-severity": "4.8"
              }
            },
            {
              "id": "OJS-CFG-CAP-001",
              "name": "CAPTCHA disabled — no automated-access protection on login and registration",
              "shortDescription": {
                "text": "CAPTCHA disabled — no automated-access protection on login and registration"
              },
              "fullDescription": {
                "text": "Neither reCAPTCHA nor ALTCHA is enabled in [captcha]. No bot protection on registration/login."
